import React, {useState, useEffect} from 'react';
import { makeStyles, withStyles } from '@material-ui/core/styles';
import Stepper from '@material-ui/core/Stepper';
import Step from '@material-ui/core/Step';
import StepLabel from '@material-ui/core/StepLabel';
import StepContent from '@material-ui/core/StepContent';
import StepConnector from '@material-ui/core/StepConnector';
import Card from '@material-ui/core/Card';
import CardContent from '@material-ui/core/CardContent';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemSecondaryAction from '@material-ui/core/ListItemSecondaryAction';
import ListItemText from '@material-ui/core/ListItemText';
import Typography from '@material-ui/core/Typography';
import Box from '@material-ui/core/Box';
import Collapse from '@material-ui/core/Collapse';
import IconButton from '@material-ui/core/IconButton';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import KeyboardArrowDownIcon from '@material-ui/icons/KeyboardArrowDown';
import KeyboardArrowUpIcon from '@material-ui/icons/KeyboardArrowUp';

const useStyles = makeStyles((theme) => ({
root: {
width: '100%',
},
button: {
marginTop: theme.spacing(1),
marginRight: theme.spacing(1),
}
}));


const useRowStyles = makeStyles({
    root: {
      '& > *': {
        borderBottom: 'unset',
      },
    },
  });


const QontoConnector = withStyles({
    alternativeLabel: {
    top: 10,
    left: 'calc(-50% + 16px)',
    right: 'calc(50% + 16px)',
    },
    line: {
    borderColor: '#eaeaf0',
    borderTopWidth: 3,
    borderRadius: 1,
    },
})(StepConnector);


export default function VerticalLinearStepper(props) {
const classes = useStyles();
const [activeStep, setActiveStep] = React.useState(0);
const [steps, setSteps] = useState([]);

function generate(element) {
    return [0, 1, 2].map((value) =>
      React.cloneElement(element, {
        key: value,
      }),
    );
  }

useEffect(()=>{
    setSteps(props.data.reverse());
},[])

function Row(props) {
    const { row } = props;
    const [open, setOpen] = React.useState(false);
    const classes = useRowStyles();
  
    return (
      <React.Fragment>
        {row.docID ? 
        //File
        <TableRow className={classes.root}>
          <TableCell>
            <IconButton aria-label="expand row" size="small" onClick={() => setOpen(!open)}>
              {open ? <KeyboardArrowUpIcon /> : <KeyboardArrowDownIcon />}
            </IconButton>
          </TableCell>
          <TableCell component="th" scope="row">
            {row.docID.split("-")[[row.docID.split("-").length - 1]]}
          </TableCell>
          <TableCell style={{color:'#3f51b5'}} align="right"> {row.docHash}</TableCell>
          <TableCell align="right">{row.workflowID}</TableCell>
          <TableCell align="right">{row.initedBy}</TableCell>
          <TableCell align="right">{row.eventFor}</TableCell>
          <TableCell align="right">{row.eventStatus}</TableCell>
        </TableRow>
        :
        //Workflow 
        <TableRow className={classes.root}>
        <TableCell>
          <IconButton aria-label="expand row" size="small" onClick={() => setOpen(!open)}>
            {open ? <KeyboardArrowUpIcon /> : <KeyboardArrowDownIcon />}
          </IconButton>
        </TableCell>
        <TableCell component="th" scope="row" style={{fontWeight:800}}>
          {row.WorkflowName}
        </TableCell>
        <TableCell style={{color:'#3f51b5'}} align="right"> {row.WorkflowHash}</TableCell>
        <TableCell align="right">{row.WorkflowId}</TableCell>
        <TableCell align="right">{row.OrganizationName}</TableCell>
        <TableCell align="right">{row.CompanyName}</TableCell>
        <TableCell align="right">{row.StepsCount}</TableCell>
        {/*
        <TableCell align="right">{row.approveStepsCount}</TableCell>
        <TableCell align="right">{row.createdBy}</TableCell>
        <TableCell align="right">{row.createdDate}</TableCell>
        <TableCell align="right">{row.updatedBy}</TableCell>
        <TableCell align="right">{row.updatedDate}</TableCell> */}
        
      </TableRow>
        }
        <TableRow>
          <TableCell style={{ paddingBottom: 0, paddingTop: 0 }} colSpan={6}>
            <Collapse in={open} timeout="auto" unmountOnExit>
              <Box margin={1}>
                    <Typography variant="body2" gutterBottom component="div">
                    {row.docID ? row.eventComments:row.ReferenceTicket}
                    </Typography>
              </Box>
            </Collapse>
          </TableCell>
        </TableRow>
      </React.Fragment>
    );
  }

function getStepContentTable(step, ind) {
    console.log(step);
    return (
    <Box boxShadow={3} style={{padding:5,marginLeft:30*ind, background:'rgb(238 238 238)'}}>
        <Table aria-label="collapsible table">
            <TableHead>
            {step.docID ? 
            <TableRow>
                <TableCell />
                <TableCell>Invoice ID</TableCell>
                <TableCell align="right">Block Hash</TableCell>
                <TableCell align="right">Workflow ID</TableCell>
                <TableCell align="right">Inited By</TableCell>
                <TableCell align="right">Event For</TableCell>
                <TableCell align="right">Event Status</TableCell>
            </TableRow>
            :
            <TableRow>
                <TableCell />
                <TableCell>Workflow Name</TableCell>
                <TableCell align="right">Block Hash</TableCell>
                <TableCell align="right">Workflow ID</TableCell>
                <TableCell align="right">Organization Name</TableCell>
                <TableCell align="right">Company Name</TableCell>
                <TableCell align="right">Steps Count</TableCell>
                {/*
                <TableCell align="right">Approve StepsCount</TableCell>
                <TableCell align="right">Created By</TableCell>
                <TableCell align="right">Created Date</TableCell>
                <TableCell align="right">Updated By</TableCell>
                <TableCell align="right">Updated Date</TableCell> */}
            </TableRow>
            }
            </TableHead>
            <TableBody>
                <Row key={ind} row={step} />
            </TableBody>
        </Table>
      </Box>
    )
}

function getStepContent(step, ind) {
return (
<Box boxShadow={3} style={{width:600,padding:5,marginLeft:30*ind, background:'rgb(238 238 238)'}}>
        <CardContent>
                {/* <Typography className={classes.title} color="textSecondary" gutterBottom>
                Document Initialization
                </Typography> */}
                {step.invoiceId ? 
                <div className={classes.demo}>
                <List>
                    <ListItem>
                    <ListItemText
                        primary="Document ID"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.docID.split("-")[[step.docID.split("-").length - 1]]}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Block Hash"
                    />
                    <ListItemSecondaryAction>
                        <p style={{color:'#3f51b5'}}>{step.docHash}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow ID"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowID}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Inited By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.initedBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event For"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventFor}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event Description"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventComments}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Event Status"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.eventStatus}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    </List>
                    </div>
                :
                <div className={classes.demo}>
                <List>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Block Hash"
                    />
                    <ListItemSecondaryAction>
                        <p style={{color:'#3f51b5'}}>{step.workflowHash}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Id"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowId}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Organization Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.orgName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Company Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.companyName}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Workflow Description"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.workflowDescription}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Review StepsCount"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.reviewStepsCount}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Approve StepsCount"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.approveStepsCount}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Created By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.createdBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Created Date"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.createdDate}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    {step.updatedBy ?
                    <div>
                    <ListItem>
                    <ListItemText
                        primary="Updated By"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.updatedBy}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    <ListItem>
                    <ListItemText
                        primary="Updated Date"
                    />
                    <ListItemSecondaryAction>
                        <p>{step.updatedDate}</p>
                    </ListItemSecondaryAction>
                    </ListItem>
                    </div>
                    :''}
                    {/* <ListItem>
                    <ListItemText
                        primary="Com Name"
                    />
                    <ListItemSecondaryAction>
                        <p>{dateFormat(step.createdBy, "dd/mm/yyyy hh:mm:ss")}</p>
                    </ListItemSecondaryAction>
                    </ListItem> */}
                </List>
            </div>
                }
        </CardContent>
</Box>
    )
}


    
const handleNext = (index) => {
setActiveStep(index);
};



return (
<div className={classes.root}>
    <Stepper activeStep={activeStep} orientation="vertical" connector={<QontoConnector />}>
    {steps.map((data, index) => (
        <Step active={true}  key={index} >
        {JSON.parse(data.Record).event ? <StepLabel >{JSON.parse(data.Record).event ? `${JSON.parse(data.Record).event.toUpperCase()} STEP`:''}</StepLabel>:''}
        <StepContent>                
            <div>{getStepContentTable(JSON.parse(data.Record), index)}</div>
        </StepContent>
        </Step>
    ))}
    </Stepper>
</div>
);
}