/*eslint-disable*/
import React, { useState, useEffect, forwardRef } from "react";
// @material-ui/core components
import {
  makeStyles,
  withStyles,
  Typography,
  Chip,
  Divider,
  LinearProgress,
  ListItemText
} from "@material-ui/core";
// core components

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
import QRCode from 'qrcode'
import { CopyToClipboard } from 'react-copy-to-clipboard';
import InputLabel from '@material-ui/core/InputLabel';
import MenuItem from '@material-ui/core/MenuItem';
import FormControl from '@material-ui/core/FormControl';
import Select from '@material-ui/core/Select';
import Stepper from '@material-ui/core/Stepper';
import Step from '@material-ui/core/Step';
import StepLabel from '@material-ui/core/StepLabel';
import StepContent from '@material-ui/core/StepContent';
import StepConnector from '@material-ui/core/StepConnector';
import List from '@material-ui/core/List';
import 'react-perfect-scrollbar/dist/css/styles.css';
import { useDispatch, useSelector } from "react-redux";
import WizardView from './WizardView';

const useStyle = makeStyles(styles);
const useStyles = makeStyles((theme) => ({
  list: {
    color: 'black'
  }

}));
const FileAdvanceView = forwardRef((props, ref) => {
  const Token = useSelector(state => state.userReducer.Token) || localStorage.getItem('cooljwt');
  const decoded = jwt.decode(Token);
  const classes = useStyle();
  const classesList = useStyles();
  const [isLoading, setIsLoading] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const [qrCode, setQrCode] = useState(null);
  const [blockChainData, setBlockChainData] = useState([]);
  const [versions, setVersions] = useState([]);
  const [fileData, setFileData] = useState(props.fileData);
  const [version, setVersion] = useState(fileData.version);
  const [workflow, setWorkflow] = useState(null);

//Get BlockChain View
  const getBlockChainData = () => {
    return new Promise((res, rej) => {
      axios({
        method: "get", //you can set what request you want to be
        //url: `${process.env.REACT_APP_LDOCS_API_BOOKCHAIN_URL}/api/queryhistory/1234-doc-32432`
        url: `http://40.123.192.228:8899/api/queryhistory/1234-doc-32432`
      })
        .then((response) => {
          if (response.data.length !== 0) {
            setBlockChainData(response.data);
            res(response.data);
          }
        })
        .catch((err) => {
          console.log(err);
        })
    })
  }
//Get QrR Code
  const getQrCode = () => {
    return new Promise((res, rej) => {
      QRCode.toDataURL(fileData.invoiceId)
        .then(url => {
          setQrCode(url)
          res(url);
        })
        .catch(err => {
          console.error(err)
        });
    })
  }

  //Change Version 
  const Changehandler = (event) => {
    setIsLoading(true);
    const File = versions.find(item => item.version == event.target.value);
    setFileData(File);
    setVersion(File.version);
    setIsLoading(false);

  }

//BLockChain Stepper
  const QontoConnector = withStyles({
    alternativeLabel: {
      top: 3,
      left: 'calc(-50% + 16px)',
      right: 'calc(50% + 16px)',
    },
    line: {
      borderColor: '#eaeaf0',
      borderTopWidth: 3,
      borderRadius: 1,
    },
  })(StepConnector);

  //Step Content
  function getStepContent(stp, ind) {
    var step = JSON.parse(stp.Record);
    return (
      <Card variant="outlined"
        style={{ padding: "10px", marginTop: -5 }}
      >
        <CardHeader>
          <Typography variant="subtitle2" component="h2">
            {step.event.toUpperCase()} STEP
        </Typography>
        </CardHeader>
        <Divider />
        <CardBody>
          <GridContainer
            style={{ padding: "10px" }}
          >
            <GridItem
              xs={12}
              sm={12}
              md={8}
              lg={8}
            >
              <Typography variant="subtitle2" component="h2">
                {step.eventFor.toUpperCase()}
              </Typography>
            </GridItem>
            <GridItem
              xs={12}
              sm={12}
              md={4}
              lg={4}
            >
              <Chip size="small" label={step.eventStatus.toUpperCase()} />
            </GridItem>
          </GridContainer>
        </CardBody>
        <Divider />
        <CardHeader
        >
          <Typography variant="subtitle2" component="h2"
            style={{ padding: "10px" }}
          >
            {step.eventInitDate.toUpperCase()}
          </Typography>
        </CardHeader>
      </Card>)
  }

  //Load All Functions
  const loadFunctions = async () => {
    setIsLoading(true);
    getQrCode().then(
      getFileVersions().then(
        fileData.initWorkFlow ?
          // getBlockChainData().then(blockChainData => {
            getWorkflowSteps().then(res => {
              typeof res == 'object' ?
                setWorkflow(res) : setWorkflow(null);
              console.log(res);
              setIsLoading(false);
            // });
          })
          : () => {
            setIsLoading(false)
            setWorkflow(null)
          })
    )
  }

  //Get Inited Workflow Details
  const getWorkflowSteps = async () => {
    console.log(fileData.workflowId);
    return new Promise((res, rej) => {
      axios({
        method: "get",
        url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/getWorkflowDetailsById/${fileData.workflowId}`,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          console.log(response);
          res(response.data);
        })
        .catch((err) => {
          console.log(err);
        })
    })
  };
  //Get File version
  const getFileVersions = async () => {
    return new Promise((res, rej) => {
      let data = {
        tenantId: fileData.tenantId,
        organizationId: fileData.organizationId,
        invoiceId: fileData.invoiceId
      };
      axios({
        method: "post",
        url: `${process.env.REACT_APP_LDOCS_API_URL}/invoice/getInvoiceVersions`,
        data: data,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          setVersions(response.data);
          res(response.data);
        })
        .catch((err) => {
          console.log(err);
        })
    })
  };

//Use Effect Hook
  useEffect(() => {
    loadFunctions();
  }, [fileData]);

  {
    return (
      isLoading ?
        <LinearProgress /> :
        <GridContainer ref={ref}>
          <GridItem
            xs={12}
            sm={12}
            md={12}
            lg={blockChainData.length !== 0 ? 8 : 12}
          >
            <Card
              style={{ padding: "20px" }}
            >
              <Typography variant="h6" component="h2">
                Invoice Details
              </Typography>
              <GridContainer
                style={{ marginTop: "20px", marginBottom: "20px" }}
              >
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                >
                  <List className={classesList.list}>
                    <ListItemText primary="Invoice ID" secondary={fileData.invoiceId} />
                    <ListItemText primary="Invoice Hash" secondary={fileData.invoiceHash} />
                    <ListItemText primary="Invoice Description" secondary={fileData.ref} />
                    <ListItemText primary="Discount %" secondary={fileData.discountPercent} />
                    <ListItemText primary="Gross Amount" secondary={fileData.grossAmt.toFixed(2)} />
                    <ListItemText primary="Net Amount" secondary={fileData.netAmt.toFixed(2)} />
                  </List>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                >
                  <List className={classesList.list}>
                    <ListItemText primary=" Vendor ID" secondary={fileData.vendorId} />
                    <ListItemText primary="Vendor Name" secondary={fileData.vendorName} />
                    <ListItemText primary="Created Date" secondary={fileData.invoiceDate} />
                    <ListItemText primary="Item Count" secondary={fileData.items.length} />
                  </List>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ textAlign: 'center' }}
                >
                  <GridContainer>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                    >
                      <FormControl variant="outlined" className={classes.formControl}>
                        <InputLabel id="demo-simple-select-outlined-label">Invoice Version</InputLabel>
                        <Select
                          labelId="demo-simple-select-outlined-label"
                          id="demo-simple-select-outlined"
                          value={version}
                          style={{ width: 150 }}
                          onChange={Changehandler}
                          label="Version"
                        >
                          {versions.map(vrsn => {
                            return <MenuItem key={vrsn.version} value={vrsn.version}>Version {vrsn.version}</MenuItem>
                          })}
                        </Select>
                      </FormControl>
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                    >
                      <CopyToClipboard text={fileData.invoiceId}
                        onCopy={() => setIsCopied(!isCopied)}>
                        <img style={{ width: 200 }} src={qrCode} />
                      </CopyToClipboard>
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={12}
                      lg={12}
                    >
                      <CopyToClipboard text={fileData.invoiceId}
                        onCopy={() => setIsCopied(!isCopied)}>
                        <small style={{ cursor: 'pointer', color: isCopied ? 'blue' : 'black' }}>{isCopied ? 'Copied' : fileData.invoiceId.slice(0, 9)}....</small>
                      </CopyToClipboard>
                    </GridItem>
                  </GridContainer>
                </GridItem>
              </GridContainer>
            </Card>
            <GridContainer style={{ marginTop: -20 }}>
              <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={12}
              >
                <Card
                  style={{ padding: "20px" }}
                >
                  <WizardView items={fileData.items} isWorkflowInit={fileData.initWorkFlow} blockChainData={blockChainData} workflow={workflow} attachments={fileData.attachments} />
                </Card>
              </GridItem>
            </GridContainer>
          </GridItem>
          {blockChainData.length !== 0 ?
            <GridItem
              xs={12}
              sm={12}
              md={12}
              lg={4}
            >
              <Card
                style={{ padding: "10px" }}
              >
                <Typography variant="h6" component="h2">
                  Workflow History
         </Typography>
                <Stepper orientation="vertical" connector={<QontoConnector />}>
                  {blockChainData.map((data, index) => (
                    <Step active={true} key={index}>
                      <StepLabel >{JSON.parse(data.Record).docHash}</StepLabel>
                      <StepContent>
                        <div>{getStepContent(data, index)}</div>
                      </StepContent>
                    </Step>
                  ))}
                </Stepper>
              </Card>
            </GridItem>
            : ''
          }

        </GridContainer>
    );
  }
});


export default FileAdvanceView;